1301   bool isRemovable(Instruction *I) {
1302     assert(getLocForWrite(I) && "Must have analyzable write");
1303 
1304     // Don't remove volatile/atomic stores.
1305     if (StoreInst *SI = dyn_cast<StoreInst>(I))
1306       return SI->isUnordered();
1307 
1308     if (auto *CB = dyn_cast<CallBase>(I)) {
1309       // Don't remove volatile memory intrinsics.
1310       if (auto *MI = dyn_cast<MemIntrinsic>(CB))
1311         return !MI->isVolatile();
1312 
