1314       // by a free.
1315       if (CB->isLifetimeStartOrEnd())
1316         return false;
1317 
1318       return CB->use_empty() && CB->willReturn() && CB->doesNotThrow() &&
1319              !CB->isTerminator();
1320     }
1321 
1322     return false;
